import java.util.Scanner;
import org.owasp.encoder.Encode;

public class SecureXSSProtection {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Sanitize and escape user input before outputting it to the HTML response
        String sanitizedName = Encode.forHtml(name);

        System.out.println("<p>Welcome, " + sanitizedName + "!</p>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
